def run_factorial_examples() -> dict[str, int]:
    """Return sample factorial results for notebook demonstration."""
    samples: Final[tuple[int, ...]] = (0, 1, 3, 5)
    return {str(value): factorial(value) for value in samples}

def validate_factorial_behavior() -> dict[str, str]:
    """Return validation outcomes without executing code at module scope."""
    outcomes: dict[str, str] = {}

    try:
        factorial(-1)
    except ValueError as exc:
        outcomes["negative_input"] = str(exc)

    try:
        factorial(2.5)
    except TypeError as exc:
        outcomes["float_input"] = str(exc)

    try:
        factorial(True)
    except TypeError as exc:
        outcomes["bool_input"] = str(exc)

    return outcomes

